steps.code:
selectWindow("Osteosarcoma_01.tif");
run("Duplicate...", "title=nuclei_source");
run("Split Channels");
// Keep blue channel (DAPI/nuclei), close the rest
selectWindow("nuclei_source (red)"); close();
selectWindow("nuclei_source (green)"); close();
rename("nuclei_blue");

// === Approach 1: Otsu threshold (no preprocessing) ===
selectWindow("nuclei_blue");
run("Duplicate...", "title=approach_01_otsu");
setAutoThreshold("Otsu dark");
run("Convert to Mask");

// === Approach 2: Triangle threshold (no preprocessing) ===
selectWindow("nuclei_blue");
run("Duplicate...", "title=approach_02_triangle");
setAutoThreshold("Triangle dark");
run("Convert to Mask");

// === Approach 3: Li threshold (no preprocessing) ===
selectWindow("nuclei_blue");
run("Duplicate...", "title=approach_03_li");
setAutoThreshold("Li dark");
run("Convert to Mask");

// === Approach 4: Gaussian blur (sigma=2) + Otsu ===
selectWindow("nuclei_blue");
run("Duplicate...", "title=approach_04_gauss_otsu");
run("Gaussian Blur...", "sigma=2");
setAutoThreshold("Otsu dark");
run("Convert to Mask");

// === Approach 5: Gaussian blur (sigma=2) + Otsu + Watershed ===
selectWindow("nuclei_blue");
run("Duplicate...", "title=approach_05_gauss_otsu_ws");
run("Gaussian Blur...", "sigma=2");
setAutoThreshold("Otsu dark");
run("Convert to Mask");
run("Watershed");

// === Approach 6: Median filter (r=2) + Otsu + Watershed ===
selectWindow("nuclei_blue");
run("Duplicate...", "title=approach_06_median_otsu_ws");
run("Median...", "radius=2");
setAutoThreshold("Otsu dark");
run("Convert to Mask");
run("Watershed");

// === Approach 7: Gaussian blur + Triangle + Watershed ===
selectWindow("nuclei_blue");
run("Duplicate...", "title=approach_07_gauss_tri_ws");
run("Gaussian Blur...", "sigma=2");
setAutoThreshold("Triangle dark");
run("Convert to Mask");
run("Watershed");

// === Approach 8: Phansalkar local threshold ===
selectWindow("nuclei_blue");
run("Duplicate...", "title=approach_08_phansalkar");
run("Auto Local Threshold", "method=Phansalkar radius=15 parameter_1=0 parameter_2=0 white");

// === Approach 9: Gaussian + Otsu + Open + Watershed (morphological cleanup) ===
selectWindow("nuclei_blue");
run("Duplicate...", "title=approach_09_morph");
run("Gaussian Blur...", "sigma=2");
setAutoThreshold("Otsu dark");
run("Convert to Mask");
run("Open");
run("Watershed");

// === Approach 10: Gaussian + Huang threshold + Watershed ===
selectWindow("nuclei_blue");
run("Duplicate...", "title=approach_10_huang_ws");
run("Gaussian Blur...", "sigma=2");
setAutoThreshold("Huang dark");
run("Convert to Mask");
run("Watershed");

// Set measurements
run("Set Measurements...", "area mean centroid shape display redirect=None decimal=2");

// Run Analyze Particles on the winning mask
selectWindow("approach_09_morph");
run("Select None");
roiManager("Reset");
run("Clear Results");
run("Analyze Particles...", "size=50-Infinity circularity=0.3-1.00 display exclude clear add");

n = roiManager("count");
print("Detected nuclei: " + n);

// Show ROIs on original and flatten
selectWindow("Osteosarcoma_01.tif");
roiManager("Show All without labels");
run("Flatten");
rename("result_segmentation");

// Check what Analyze Particles expects — it detects dark objects on light background by default
// Our mask has white nuclei on black background, so we may need to invert
selectWindow("approach_09_morph");
run("Duplicate...", "title=mask_for_analysis");

// Check: set black background option and re-run
run("Options...", "iterations=1 count=1 black do=Nothing");
run("Select None");
roiManager("Reset");
run("Clear Results");
run("Set Measurements...", "area mean centroid shape display redirect=None decimal=2");
run("Analyze Particles...", "size=50-Infinity circularity=0.3-1.00 display exclude clear add");

n = roiManager("count");
print("Detected nuclei: " + n);

// The mask needs a threshold set for Analyze Particles
selectWindow("mask_for_analysis");
setThreshold(128, 255);
roiManager("Reset");
run("Clear Results");
run("Set Measurements...", "area mean centroid shape display redirect=None decimal=2");
run("Analyze Particles...", "size=50-Infinity circularity=0.3-1.00 display exclude clear add");

n = roiManager("count");
print("Detected nuclei: " + n);

selectWindow("mask_for_analysis");
getStatistics(area, mean, min, max);
print("Image stats - min: " + min + " max: " + max + " mean: " + mean);
print("Type: " + bitDepth() + "-bit");
print("Width: " + getWidth() + " Height: " + getHeight());
// Check a few pixel values in areas where we expect nuclei
v1 = getPixel(400, 200);
v2 = getPixel(700, 500);
v3 = getPixel(100, 100);
print("Pixel samples: " + v1 + ", " + v2 + ", " + v3);

// Let me recreate the winning approach cleanly from the blue channel
selectWindow("nuclei_blue");
run("Duplicate...", "title=final_mask");
run("Gaussian Blur...", "sigma=2");
setAutoThreshold("Otsu dark");
run("Convert to Mask");
run("Open");
run("Watershed");

// Now run Analyze Particles
roiManager("Reset");
run("Clear Results");
run("Set Measurements...", "area mean centroid shape display redirect=None decimal=2");
run("Analyze Particles...", "size=50-Infinity circularity=0.3-1.00 display exclude clear add");

n = roiManager("count");
print("Detected nuclei: " + n);

// List all open windows
list = getList("image.titles");
for (i = 0; i < list.length; i++) {
    print(list[i]);
}

// Explicitly select final_mask and check it
selectWindow("final_mask");
getStatistics(area, mean, min, max);
print("final_mask stats - min: " + min + " max: " + max + " mean: " + mean);

// Try running Analyze Particles with threshold set
setThreshold(128, 255);
roiManager("Reset");
run("Clear Results");
run("Analyze Particles...", "size=50-Infinity circularity=0.30-1.00 show=Nothing display clear add");
n = roiManager("count");
print("Detected nuclei: " + n);

// Debug: try to create a selection from the mask
selectImage("final_mask");
setThreshold(128, 255);
run("Create Selection");
type = selectionType();
print("Selection type: " + type);
if (type != -1) {
    getSelectionBounds(x, y, w, h);
    print("Bounds: " + x + ", " + y + ", " + w + ", " + h);
}

// Try without exclude and with more relaxed parameters
selectImage("final_mask");
run("Select None");
setThreshold(128, 255);
roiManager("Reset");
run("Clear Results");
run("Analyze Particles...", "size=50-Infinity show=Nothing display clear add");
n = roiManager("count");
print("Without filters: " + n);

// Close intermediate images and start fresh for the final segmentation
close("approach_*");
close("mask_for_analysis");
close("final_mask");
close("Drawing*");
close("result_segmentation");

// Recreate the best approach in one go
selectWindow("nuclei_blue");
run("Duplicate...", "title=best_mask");
run("Gaussian Blur...", "sigma=2");
setAutoThreshold("Otsu dark");
run("Convert to Mask");
run("Open");
run("Watershed");

// Verify we're on the right image
print("Active: " + getTitle());
getStatistics(area, mean, min, max);
print("Stats: min=" + min + " max=" + max + " mean=" + mean);

// Now Analyze Particles
roiManager("Reset");
run("Clear Results");
run("Set Measurements...", "area mean centroid shape display redirect=None decimal=2");
run("Analyze Particles...", "size=50-Infinity circularity=0.30-1.00 show=Nothing display exclude clear add");
n = roiManager("count");
print("Nuclei found: " + n);

// Absolute minimal Analyze Particles
selectWindow("best_mask");
setThreshold(128, 255);
roiManager("Reset");
run("Analyze Particles...", "size=0-Infinity show=Nothing clear add");
n = roiManager("count");
print("Minimal filter: " + n);

// If still 0, try inverting
if (n == 0) {
    run("Invert");
    setThreshold(0, 127);
    run("Analyze Particles...", "size=0-Infinity show=Nothing clear add");
    n = roiManager("count");
    print("After invert: " + n);
    if (n > 0) {
        run("Invert"); // revert
    }
}

// Remove spatial calibration — sizes in pixels
selectWindow("best_mask");
run("Properties...", "unit=pixel pixel_width=1 pixel_height=1");
setThreshold(128, 255);

roiManager("Reset");
run("Set Measurements...",
    "area mean centroid shape display redirect=None decimal=2");
run("Analyze Particles...",
    "size=100-5000 circularity=0.30-1.00 show=Nothing "
